SELECT 
FROM NIC01B
WHERE USE_CCD = 'Y'

    AND CS_NM LIKE '%' || #{custNm} || '%'


    AND CS_TYP_CD = #{custTpCd}


    AND RSK_GRD_CD = #{riskGrd}


    AND KYC_STS_CCD = #{kycStCd}

ORDER BY REG_DT DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM NIC01B
WHERE USE_CCD = 'Y'

    AND CS_NM LIKE '%' || #{custNm} || '%'


    AND CS_TYP_CD = #{custTpCd}


    AND RSK_GRD_CD = #{riskGrd}


    AND KYC_STS_CCD = #{kycStCd}
